import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { generateRoadmapPrompt, processAIRequest } from "@/lib/ai-service";

export async function GET() {
    try {
        // In a real app, get userId from session
        const user = await prisma.user.findUnique({
            where: { email: "student@example.com" },
            include: { learningPath: true, assessments: { orderBy: { createdAt: "desc" }, take: 1 } },
        });

        if (!user) {
            return NextResponse.json({ error: "User not found" }, { status: 404 });
        }

        // If roadmap exists, return it
        if (user.learningPath) {
            return NextResponse.json({
                roadmap: user.learningPath.roadmap,
                resources: user.learningPath.resources,
                majorSuggestions: user.learningPath.majorSuggestions,
            });
        }

        // If no roadmap but assessment exists, generate one
        if (user.assessments.length > 0) {
            const lastAssessment = user.assessments[0];

            // Get all subject scores for this user
            const subjects = await prisma.subject.findMany({
                where: { userId: user.id },
            });

            const prompt = generateRoadmapPrompt(subjects.map(s => ({
                subject: s.name,
                score: s.performance,
                answers: [], // Mocking answers for prompt simplicity
            })));

            const aiResponse = await processAIRequest(prompt);

            // Store in database
            const newPath = await prisma.learningPath.create({
                data: {
                    userId: user.id,
                    roadmap: aiResponse.roadmap as any,
                    resources: aiResponse.resources as any,
                    majorSuggestions: aiResponse.majorSuggestions,
                },
            });

            return NextResponse.json(aiResponse);
        }

        return NextResponse.json({ error: "No diagnostic assessment found. Please take the test first." }, { status: 400 });

    } catch (error) {
        console.error("Learning Path Error:", error);
        return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
    }
}
